-- ── Rocket.Chat ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Rocket.Chat is an open-source team chat and collaboration platform that can be self-hosted or used via managed cloud plans, with a focus on security and data sovereignty.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (free self-hosted Community edition, plus paid Pro and Enterprise plans)$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community); Pro from $8/user/month billed annually$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$51-200 employees (estimates vary by source, roughly 150-176)$q$, company_size),
  headquarters = COALESCE($q$Wilmington, Delaware, United States (with an R&D office in Porto Alegre, Brazil)$q$, headquarters),
  languages = ARRAY[$q$Available in 30+ interface languages via community translation$q$]::text[],
  seo_title = COALESCE($q$Rocket.Chat Review 2026: Pricing, Features, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Rocket.Chat's free and paid plans compare, what features are included, and whether this open-source team chat platform fits your needs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Rocket.Chat is an open-source team chat and collaboration platform founded in 2015 by Gabriel Engel, built as an alternative to proprietary messaging tools like Slack and Microsoft Teams with an emphasis on self-hosting, data sovereignty, and security-focused deployments. The company behind the product, Rocket.Chat Technologies Corp., lists Wilmington, Delaware as its corporate headquarters while maintaining a research and development office in Porto Alegre, Brazil, where the project originated; employee counts across data providers range roughly from 150 to just over 175 people. The platform's free, self-hosted Community edition supports up to fifty users and includes end-to-end encryption, unlimited message history, video conferencing integration, and data loss prevention controls, making it a popular choice for privacy-conscious teams, developers, and organizations that need to keep chat data within their own infrastructure. Paid tiers extend capacity and add enterprise features: the Pro plan is commonly cited at eight dollars per user per month on annual billing and supports up to five hundred users with advanced hosting options, white-label distribution rights, and standard support, while custom-quoted Enterprise, Government, and Defense plans add high availability architecture, advanced governance and audit trails, SCIM and SSO provisioning, FIPS 140-3 validated cryptography, federation capabilities, and air-gapped or SCIF-ready deployment options for regulated and public-sector customers. Rocket.Chat differentiates itself from many SaaS chat competitors by offering full source-code access and flexible deployment models spanning on-premises, private cloud, isolated VPC or VPN, and sovereign cloud environments, which has made it a common choice for government agencies, defense contractors, and organizations with strict data residency requirements. It is important not to confuse Rocket.Chat with the similarly-prefixed Rocket Matter, a completely unrelated legal practice management SaaS product for law firms; the two companies share no ownership, technology, or business relationship beyond the coincidental name similarity. Rocket.Chat's core feature set includes channel-based messaging, direct messages, voice and video calling, screen sharing, mobile apps for iOS and Android, omnichannel customer service tools, and an extensive apps marketplace and API for building custom integrations and bots, positioning it as both a team collaboration tool and a customer-facing communication platform depending on how an organization deploys it.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '376dca7b-3bc4-46f6-ae09-635baf27d62b';

