-- ── RomM ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$RomM is a free, open-source, self-hosted ROM manager and player that lets users organize, enrich, and play retro video game collections from a web browser.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English (web interface)$q$]::text[],
  seo_title = COALESCE($q$RomM Review: Self-Hosted Open-Source ROM Manager Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what RomM is, how its self-hosted ROM management features work, and what it takes to run this open-source retro gaming tool.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RomM, short for ROM Manager, is a free and open-source, self-hosted application for organizing, enriching, and playing retro video game ROM collections through a web browser, created by a developer known online as zurdi15 and maintained under the rommapp GitHub organization. The project is licensed under the GNU Affero General Public License version 3 (AGPL-3.0) and has attracted a sizable open-source following, with its GitHub repository accumulating over 11,000 stars. RomM is designed for the self-hosting and homelab community, typically deployed via Docker on a home server or NAS alongside other self-hosted applications, and it explicitly positions itself against tracking, upsells, and shareholder-driven software, describing itself as built for its users rather than for commercial gain. The core functionality scans a user's existing ROM library and enriches it with metadata pulled from sources including IGDB, ScreenScraper, MobyGames, RetroAchievements, Hasheous, and LaunchBox, automatically fetching box art, descriptions, and platform information while correctly recognizing and grouping multi-file ROM sets, DLCs, mods, and manuals to avoid duplicate library entries. RomM supports metadata and organization across more than four hundred gaming platforms and includes in-browser emulation through EmulatorJS and Ruffle (for Flash content), meaning users can play many supported games directly in a web browser without installing separate emulator software. The platform includes a first-class multi-user system with configurable per-user permissions and OpenID Connect (OIDC) single sign-on support, letting a self-hoster share limited, controlled access to their library with friends or family while retaining full administrative control. Additional integrations include RetroAchievements support for earning achievements in classic games, and companion or community-built clients spanning an official Android app (Argosy), custom firmware handheld device support (Grout), and community projects covering iOS, RetroArch synchronization, desktop clients, SteamOS, and Nintendo Switch homebrew, as well as a Discord bot integration and an official Playnite plugin. Because RomM is a community open-source project rather than a commercial company, there is no pricing, corporate headquarters, or verified employee count to report, and its founding date is not clearly documented in public sources, though its GitHub activity and release history show active, ongoing development as of 2026.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '27cd08d4-3907-484c-bde4-d06e726c6674';

