  languages = ARRAY[$q$English, French, Spanish, Portuguese (Brazil), Italian, Russian, Ukrainian, Czech, Greek, Turkish, German, Vietnamese, Bulgarian$q$]::text[],
  seo_title = COALESCE($q$RosarioSIS Review: Free Open-Source Student Information System$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what RosarioSIS offers schools for free, from grading and scheduling to attendance and billing, plus its open-source licensing details.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RosarioSIS is a free, open-source student information system, also referred to as a school management system or school ERP, created by developer François Jacquet and released under the GNU General Public License version 2. The project traces its roots to 2012, when it was developed for Nuestra Señora del Rosario, a school in Colombia, building on an earlier source project called Centre/SIS that dates back to 2006. RosarioSIS is designed primarily for K-12 schools but is flexible enough to adapt to other educational institutions such as universities, academies, or vocational institutes. The platform bundles several modules into a single web application: student records and enrollment, a comprehensive grade book allowing teachers to define grade ranges, weight assignments, and track coursework toward quarterly and semester grades, report cards and transcripts, class and individual student scheduling, electronic attendance tracking that lets teachers submit records instantly to the school office, student billing for assigning fees and tracking payments and balances, as well as discipline and food service modules. The software has a responsive design that works on tablets and smartphones and has been translated by its community into a substantial number of languages, including French, Spanish, Portuguese (Brazil), Italian, Russian, Ukrainian, Czech, Greek, Turkish, German, Vietnamese, and Bulgarian, in addition to its default English interface, making it accessible to schools well beyond English-speaking countries. It also integrates with the Moodle learning management system and offers numerous free and premium add-ons for schools that want to extend the core functionality. Technically, RosarioSIS requires a PHP runtime of at least version 5.5.9 and either PostgreSQL 9.2 or MySQL 5.6 / MariaDB as its database backend, and schools are expected to self-host the application on their own or a third-party server since there is no official managed cloud version. The project's stated philosophy emphasizes that RosarioSIS is free and will always remain so, framing this as a matter of giving schools strategic autonomy and digital sovereignty over their student data rather than depending on a proprietary vendor. Because it is a community-driven open-source project rather than a venture-backed company, there is no formal pricing structure, corporate headquarters, or publicly reported employee headcount; support is provided through community forums, documentation, and the project's GitHub and GitLab repositories.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '54383e70-4d96-4382-b653-361b0eb6367d';

