-- ── Rosegarden ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Rosegarden is a free, open-source audio and MIDI sequencer with a full music notation editor, built for Linux.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(1993, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English (interface); developed for Linux/ALSA/KDE environments$q$]::text[],
  seo_title = COALESCE($q$Rosegarden Review: Free Open-Source MIDI Sequencer for Linux$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what Rosegarden offers musicians on Linux, from MIDI sequencing to notation editing, and how this open-source project got started.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Rosegarden is a free, open-source music composition and editing environment for Linux that combines a track-oriented MIDI and audio sequencer with a full music notation editor. Its roots trace back to 1993, when it began as an academic project at the University of Bath started by Chris Cannam and Andy Green; a Linux port followed in 1995 with developer Richard Bown joining, and Guillaume Laurent joined in 1996 during its early C/Athena-based phase. The current incarnation of the project, which shares its name and general concept with the original but is a fresh codebase, restarted at the beginning of 2000 with a new SourceForge presence, and Cannam, Bown, and Laurent led development through roughly 2000 to 2003 up to the 1.0 release. Leadership passed to D. Michael McIntyre from around 2003 to 2008, who continued as a primary maintainer through 2017, and as of 2023 Ted Felix has led ongoing development and releases. Rosegarden is licensed under the GNU General Public License, allowing free redistribution and modification, and the project is aimed at composers, musicians, music students, and small studio or home recording setups looking for an integrated, no-cost alternative to commercial digital audio workstation and notation software. Distinctively, Rosegarden treats musical notation as a first-class citizen rather than a simple MIDI-to-notation conversion layer: it stores detailed information about musical structure and presentation that goes beyond what standard MIDI data alone can represent, enabling higher-quality printed notation output than most conventional MIDI sequencers can produce. On the audio and MIDI side, it supports the JACK audio server for professional audio routing, LADSPA and DSSI plugin formats for synthesis and audio processing, and advanced ALSA MIDI features including multiplexed input/output and synchronization with external hardware and software via MIDI Clock, MIDI Machine Control (MMC), and MIDI Time Code (MTC). The software also automatically assigns MIDI channels to simplify working with multiple instruments. As a long-running community open-source project rather than a commercial company, Rosegarden has no pricing tiers, corporate structure, headquarters, or reported employee count; it is distributed through SourceForge, Codeberg, and GitHub mirrors, and users typically install it via their Linux distribution's package manager or build it from source.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ae8d22a5-f1b3-47ce-81df-8d297a9c7bba';

